  for (const text of combinedTexts) {
    const marked = decodeMarkedCsv(text);
    if (marked) {
      candidates.push({ text: marked, hasHeader: true, source: 'base64_marker', length: marked.length });
      continue;
    }
    const normalized = String(text).replace(/^\uFEFF/, '');
    const hasHeader = /国家\s*,\s*账号\s*,\s*(数据开发组|部门)\s*,\s*联系人\s*,\s*邮箱/.test(normalized);
